-- FIX Date Format
-- 1. Añadir columna nueva de tipo DATE
ALTER TABLE FACT_COMPONENT_TELEMETRY 
ADD COLUMN FULL_DATE DATE;

-- 2. Rellenarla convirtiendo el entero YYYYMMDD a DATE
UPDATE FACT_COMPONENT_TELEMETRY
SET FULL_DATE = TO_DATE(TO_CHAR(DATE_KEY), 'YYYYMMDD');

-- 3. Verificar que la conversión es correcta
SELECT DATE_KEY, FULL_DATE 
FROM FACT_COMPONENT_TELEMETRY 
LIMIT 10;

-- 4. Si todo está bien, eliminar la columna antigua
ALTER TABLE FACT_COMPONENT_TELEMETRY 
DROP COLUMN DATE_KEY;

-- 5. Renombrar la nueva como DATE_KEY si quieres mantener el nombre
ALTER TABLE FACT_COMPONENT_TELEMETRY 
RENAME COLUMN FULL_DATE TO DATE_KEY;


-- FIX to unrealistic Radiation Metrics
UPDATE FACT_COMPONENT_TELEMETRY f
SET RADIATION_MSV = 
  CASE 
    WHEN f.PHASE_ID = 'PHASE-05' -- HEO
      THEN RADIATION_MSV * 120 + UNIFORM(20, 80, RANDOM())
    WHEN f.PHASE_ID = 'PHASE-04' -- LEO  
      THEN RADIATION_MSV * 15 + UNIFORM(2, 10, RANDOM())
    WHEN f.PHASE_ID = 'PHASE-03' -- MECO
      THEN RADIATION_MSV * 8
    WHEN f.PHASE_ID IN ('PHASE-02','PHASE-06') -- Launch y Reentry
      THEN RADIATION_MSV * 3
    ELSE RADIATION_MSV * 0.5 -- Tierra: prelaunch y recovery
  END;